#nullable enable // autogenerated

using MVZ2.Managers;
using MVZ2.Metas;
using MVZ2.UI.Talk;
using PVZEngine;
using UnityEngine;

namespace MVZ2.Talk
{
    public class TalkCharacterController : MonoBehaviour
    {
        #region 公有方法
        public void SetSpeaking(bool value)
        {
            speaking = value;
        }
        public void SetLeaving(bool value)
        {
            leaving = value;
        }
        public void SetDisappear(bool value)
        {
            disappearing = value;
        }
        public void SetDisappearSpeed(float value)
        {
            disappearSpeed = value;
        }
        public void SetToTheFirstLayer()
        {
            transform.SetAsLastSibling();
        }
        public void SetToTheLastLayer()
        {
            transform.SetAsFirstSibling();
        }
        public void SetVariant(NamespaceID characterID, NamespaceID? variantID)
        {
            var characterMeta = Main.ResourceManager.GetCharacterMeta(characterID);
            if (characterMeta == null)
                return;
            var variantMeta = variantID == null ? characterMeta.GetFirstVariant() : characterMeta.GetVariant(variantID);
            if (variantMeta == null)
                return;
            SetVariant(variantMeta);
        }
        public void SetVariant(TalkCharacterVariant variant)
        {
            if (portrait == null)
                return;
            var pivot = new Vector2(variant.pivotX, variant.pivotY);
            var widthExtend = variant.widthExtend;
            var viewData = Main.TalkManager.GetPortraitViewData(variant);
            portrait.ChangeVariant(viewData);
            ui.SetSprite(portrait.GetSprite());
            ui.SetPivot(pivot);
            ui.SetWidthExtend(widthExtend);
        }
        public void SetSide(CharacterSide side, bool flipX)
        {
            Vector3 scale = Vector3.zero;
            switch (side)
            {
                case CharacterSide.Left:
                    scale = new Vector3(-1, 1, 1);
                    break;
                case CharacterSide.Right:
                    scale = new Vector3(1, 1, 1);
                    break;
            }
            ui.SetFlipX(flipX);
            ui.SetScale(scale);
        }
        public void ResetMotion()
        {
            blendValue = 0;
        }
        private void OnEnable()
        {
            if (portrait == null)
            {
                portrait = Main.TalkManager.CreateCharacterPortrait();
                portrait.TextureScale = textureScale;
            }
        }
        private void OnDisable()
        {
            if (portrait != null)
            {
                portrait.Dispose();
                portrait = null;
            }
        }
        private void Update()
        {
            if (leaving)
            {
                blendValue = Mathf.SmoothDamp(blendValue, 0, ref blendVelocity, smoothTime);
            }
            else if (speaking)
            {
                blendValue = Mathf.SmoothDamp(blendValue, 1, ref blendVelocity, smoothTime);
            }
            else
            {
                blendValue = Mathf.SmoothDamp(blendValue, idleBlendValue, ref blendVelocity, smoothTime);
            }
            if (disappearing)
            {
                disappearBlend = Mathf.Clamp01(disappearBlend + disappearSpeed * Time.deltaTime);
            }
            _animator.SetFloat("Blend", blendValue);
            _animator.SetFloat("DisappearBlend", disappearBlend);
            if (leaving && blendValue <= 0.01f || disappearing && disappearBlend >= 1)
            {
                Destroy(gameObject);
            }
        }
        #endregion

        #region 属性字段
        public MainManager Main => MainManager.Instance;
        private bool speaking;
        private bool leaving;
        private bool disappearing;
        private float disappearSpeed;
        private float disappearBlend;
        private float blendValue = 0;
        private float blendVelocity;
        private CharacterPortrait? portrait;
        [SerializeField]
        private TalkCharacterUI ui = null!;
        [SerializeField]
        private Animator _animator = null!;
        [SerializeField]
        private float smoothTime = 0.1f;
        [SerializeField]
        private float idleBlendValue = 0.8f;
        [SerializeField]
        private float textureScale = 0.7f;
        #endregion

    }

    public enum CharacterSide
    {
        None,
        Left,
        Right,
        Self
    }
}